USE BD_BookingEngine;


SELECT
--*
--	COUNT(*)
	Z.Id_Zon																	AS [Z.id_Zon],
	--Z.id_ZonPadre,
	--Z.Zon_Nombre_ES																AS [Z.Zon_Nombre_ES]
	ZP.zpg_coordenadas															AS [ZP.zpg_coordenadas]

FROM			(SELECT	Id_Zon,Id_ZonPadre,Zon_Nombre_ES, 
						Zon_Nombre_EN, Zon_Nombre_pt, 
						zon_activa, Zon_TieneAeropuerto, 
						Zon_CodigoAeropuertoMasCercano,
						Zon_FechaModificacion,Zon_Tipo,
						zon_diferenciaHoraria					FROM	BD_BookingEngine.dbo.Tbl_Zona)			Z
	LEFT JOIN	(SELECT id_Zon, Fecmod,zpg_coordenadas			FROM	BD_BookingEngine.dbo.Tbl_ZonasPoligono)	ZP ON ZP.Id_Zon = Z.Id_Zon
WHERE 
	1 = 1
